CREATE TABLE transfer_uploads (id VARCHAR(36) NOT NULL, object_key VARCHAR(512) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, filename VARCHAR(255) NOT NULL, size BIGINT UNSIGNED NOT NULL, sha256 CHAR(64) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, expires_at DATETIME(6) NOT NULL, confirmed_at DATETIME(6) NULL, bound_job_id VARCHAR(36) NULL, created_by VARCHAR(64) NOT NULL, model_id VARCHAR(36) NOT NULL, created_at DATETIME(6) NOT NULL, PRIMARY KEY (id), UNIQUE KEY uq_transfer_uploads_object_key (object_key), UNIQUE KEY uq_transfer_uploads_bound_job (bound_job_id), KEY idx_transfer_uploads_cleanup (expires_at,confirmed_at), KEY idx_transfer_uploads_owner (created_by,model_id,id), CONSTRAINT fk_transfer_uploads_job FOREIGN KEY (bound_job_id) REFERENCES background_jobs (id), CONSTRAINT fk_transfer_uploads_created_by FOREIGN KEY (created_by) REFERENCES users (id), CONSTRAINT fk_transfer_uploads_model FOREIGN KEY (model_id) REFERENCES content_models (id), CONSTRAINT chk_transfer_uploads_size CHECK (size>0), CONSTRAINT chk_transfer_uploads_sha256 CHECK (sha256 REGEXP _ascii'^[a-f0-9]{64}$')) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
